// --- CONFIGURAZIONE ---
u_min := 0;
u_max := 6.28318; 
v_min := 0;
v_max := 6.28318;
steps := 350;

// --- CODICE SHADER ---

// Parametri base
float scale = 3.0; 
float r = 0.4;

// Slider A (u_mathParams.x) controlla il "Sollevamento in 4D"
// Se A = 0, il nodo è piatto in W (annodato in 3D).
// Se A > 0, solleviamo le spire in W per scioglierlo.
float lift4D = u_mathParams.x * 3.0; 

// --- 1. CURVA CENTRALE (Figure-8) ---
// Usiamo frequenze diverse per W per evitare collisioni
vec4 Curve4D = vec4(
    (2.5 + cos(2.0 * u)) * cos(3.0 * u), // X
    (2.5 + cos(2.0 * u)) * sin(3.0 * u), // Y
    1.2 * sin(4.0 * u),                  // Z (crea l'incrocio in 3D)
    lift4D * sin(2.0 * u)                // W (separa l'incrocio in 4D)
);

// Estraiamo la parte 3D per i calcoli vettoriali classici
vec3 Curve = Curve4D.xyz;

// --- 2. DERIVATA (Velocità) ---
// Calcoliamo la tangente in 3D per costruire il tubo correttamente
float dr = -2.0 * sin(2.0 * u);
vec3 dC = vec3(
    dr * cos(3.0 * u) - (2.5 + cos(2.0 * u)) * 3.0 * sin(3.0 * u),
    dr * sin(3.0 * u) + (2.5 + cos(2.0 * u)) * 3.0 * cos(3.0 * u),
    4.8 * cos(4.0 * u)
);
vec3 Tangent = normalize(dC);

// --- 3. FRAME STABILE (Global Up) ---
// Usiamo Z come up vector per evitare strozzature
vec3 Up = vec3(0.0, 0.0, 1.0);
vec3 Binorm = cross(Tangent, Up);
if (length(Binorm) < 0.001) Binorm = cross(Tangent, vec3(0.0, 1.0, 0.0));
Binorm = normalize(Binorm);
vec3 Norm = cross(Binorm, Tangent);
Norm = normalize(Norm);

// --- 4. COSTRUZIONE TUBO ---
float tube_cos = r * cos(v);
float tube_sin = r * sin(v);

// La posizione finale ha le coordinate 3D del tubo + la coordinata W della curva
vec3 pos3D = Curve + (tube_cos * Norm + tube_sin * Binorm);

// Output 4D: (X, Y, Z, W)
// W dipende dallo slider A. Se muovi A, il nodo si sposta nella 4D e si "apre".
return vec4(pos3D * 0.35, Curve4D.w);
